const BbPromise = require('bluebird');
const chai = require('chai');
const sinon = require('sinon');
const mockery = require('mockery');
const path = require('path');

chai.use(require('chai-as-promised'));
chai.use(require('sinon-chai'));

const expect = chai.expect;

// Create a child process mock
const childProcessMock = {
  exec: sinon.stub()
};

mockery.enable({ useCleanCache: true, warnOnUnregistered: false });
mockery.registerMock('child_process', childProcessMock);

// Load npm module
const npmModule = require('./lib/packagers/npm');

// Test runScripts
describe('npm runScripts', () => {
  beforeEach(() => {
    childProcessMock.exec.reset();
  });

  after(() => {
    mockery.disable();
    mockery.deregisterAll();
  });

  it('should run scripts serially', () => {
    childProcessMock.exec.yields(null, 'success', '');
    const scripts = ['echo "hello"', 'echo "world"'];

    return expect(npmModule.runScripts('myPath', 2000, scripts)).to.be.fulfilled
    .then(() => {
      expect(childProcessMock.exec).to.have.been.calledTwice;
      expect(childProcessMock.exec.firstCall).to.have.been.calledWith(
        'echo "hello"',
        {
          cwd: 'myPath',
          encoding: 'utf8',
          maxBuffer: 2000
        },
        sinon.match.any
      );
      expect(childProcessMock.exec.secondCall).to.have.been.calledWith(
        'echo "world"',
        sinon.match.any,
        sinon.match.any
      );
      return null;
    });
  });

  it('should reject if a script fails', () => {
    childProcessMock.exec.onFirstCall().yields(null, 'success', '');
    childProcessMock.exec.onSecondCall().yields(new Error('script failed'), '', 'error output');
    const scripts = ['echo "hello"', 'exit 1'];

    return expect(npmModule.runScripts('myPath', 2000, scripts)).to.be.rejectedWith('script failed');
  });

  it('should handle empty scripts array', () => {
    return expect(npmModule.runScripts('myPath', 2000, [])).to.be.fulfilled
    .then(() => {
      expect(childProcessMock.exec).to.not.have.been.called;
      return null;
    });
  });
});
